sql:
SELECT COUNT(*) AS total_in_service
FROM aircraft_fleet
WHERE status = 'in service';

SELECT category_name
FROM aircraft_categories
WHERE max_range_nm > 1000;

SELECT status
FROM aircraft_schedules
WHERE departure_date_time > '2023-10-01 12:00:00';

SELECT description
FROM aircraft_incidents
WHERE incident_severity = 'major';

SELECT route_name, MAX(distance_nm) AS max_distance
FROM flight_routes
GROUP BY route_name;

SELECT aircraft_id, SUM(maintenance_cost) AS total_maintenance_cost
FROM aircraft_maintenance
GROUP BY aircraft_id;

SELECT usage_date, flight_time
FROM aircraft_usage
WHERE status = 'completed';

SELECT AVG(maintenance_cost) AS average_maintenance_cost, SUM(maintenance_cost) AS total_maintenance_cost
FROM aircraft_maintenance
WHERE status = 'completed';

SELECT category_name, max_range_nm
FROM aircraft_categories
WHERE max_range_nm = (SELECT MAX(max_range_nm) FROM aircraft_categories);

SELECT route_name, distance_nm
FROM flight_routes
WHERE distance_nm < 2000;

SELECT maintenance_type
FROM aircraft_maintenance
WHERE status = 'completed';

SELECT fleet_name
FROM aircraft_fleet
WHERE status = 'in service';

SELECT AVG(fuel_consumed_gallons) AS average_fuel_consumed, MAX(average_speed_knots) AS max_speed
FROM aircraft_usage
WHERE average_speed_knots > 350;

SELECT aircraft_id, SUM(fuel_consumed_gallons) AS total_fuel_consumed_gallons
FROM aircraft_usage
GROUP BY aircraft_id;

SELECT spec_value
FROM aircraft_specifications
WHERE model_id = 0 AND spec_id = 0;

external_knowledge:
- The query assumes that the aircraft's usage data, maintenance records, and route assignments are available and up to date; 
- The time period of interest is the year 2023, as specified in the query; 
- The calculations for average fuel consumption, total fuel used, and total passengers carried provide insights into the efficiency and usage of the aircraft on different routes.

